import{c as a,Q as o,j as t,m as i}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Database and Stored Data","description":"","frontmatter":{},"headers":[],"relativePath":"database.md","filePath":"database.md","lastUpdated":1780022874000}'),d={name:"database.md"};function c(s,e,r,l,n,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="database-and-stored-data" tabindex="-1">Database and Stored Data <a class="header-anchor" href="#database-and-stored-data" aria-label="Permalink to &quot;Database and Stored Data&quot;">​</a></h1><p>This page documents the current SQLite schema and the metadata/analysis payloads stored in SQLite. Use it when you want to understand what the app saves, what a reset removes, or why one search mode needs a particular analysis pass first.</p><h2 id="sqlite-specification" tabindex="-1">SQLite Specification <a class="header-anchor" href="#sqlite-specification" aria-label="Permalink to &quot;SQLite Specification&quot;">​</a></h2><p>The current schema version is <code>2</code>.</p><p>The database is local user state. Normal scan, analysis, search, reset, clear, and relocation workflows modify SQLite records only; they do not rewrite audio files. The explicit exception is the separate MAEST genre tag write workflow, which is documented in <a href="./search-and-tags.html">Search &amp; Tags</a>.</p><h3 id="tracks" tabindex="-1"><code>tracks</code> <a class="header-anchor" href="#tracks" aria-label="Permalink to &quot;`tracks`&quot;">​</a></h3><p>Stores one row per indexed audio file:</p><ul><li><code>id</code>: stable local track ID.</li><li><code>path</code>: unique stored audio path.</li><li><code>size</code>: file size at scan time.</li><li><code>mtime</code>: file modification time at scan time.</li><li><code>artist</code>, <code>title</code>, <code>album</code>: selected file metadata.</li><li><code>bpm</code>, <code>musical_key</code>, <code>energy</code>, <code>duration</code>: working fields used by the UI and analysis flows.</li><li><code>metadata_json</code>: JSON object for Mutagen fields and model-derived metadata.</li><li><code>created_at</code>, <code>updated_at</code>: local row timestamps.</li></ul><p><code>metadata_json</code> must be valid JSON. The schema has triggers to reject invalid JSON on insert or update.</p><p>Use this table to answer &quot;what tracks are in the library?&quot; and &quot;what metadata or analysis summaries does the UI show for a row?&quot; The <code>path</code> is the link back to the local audio file; relocation updates that stored path only when the same files moved to a new root.</p><h3 id="embeddings" tabindex="-1"><code>embeddings</code> <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;`embeddings`&quot;">​</a></h3><p>Stores model vectors by track and embedding space:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>embedding_key</code>: currently <code>mert</code>, <code>clap</code>, or <code>maest</code>.</li><li><code>model_name</code>: model or checkpoint identifier.</li><li><code>dim</code>: vector dimension.</li><li><code>vector</code>: binary float32 vector payload.</li><li><code>updated_at</code>: local row timestamp.</li></ul><p>The primary key is <code>(track_id, embedding_key)</code>, so the same track can have MERT, CLAP, and MAEST vectors without mixing those spaces.</p><p>Use this table to check whether an embedding-backed workflow has enough data: MERT search needs <code>mert</code>, CLAP text search needs <code>clap</code>, and promoted combined classifiers need <code>mert</code> plus <code>maest</code> alongside Sonara features.</p><h3 id="library-settings" tabindex="-1"><code>library_settings</code> <a class="header-anchor" href="#library-settings" aria-label="Permalink to &quot;`library_settings`&quot;">​</a></h3><p>Stores local database-level settings such as the selected music root.</p><p>Use this table for app-level preferences tied to one database rather than one track.</p><h3 id="track-likes" tabindex="-1"><code>track_likes</code> <a class="header-anchor" href="#track-likes" aria-label="Permalink to &quot;`track_likes`&quot;">​</a></h3><p>Stores the local liked-track list:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>liked_at</code>: local timestamp for the latest like action.</li></ul><p>The primary key is <code>track_id</code>, so a track is either liked or not liked. Rows are deleted automatically when the related track is removed from the local library database. Likes are app state only; they never write to audio files or Mutagen tags.</p><h3 id="track-classifier-scores" tabindex="-1"><code>track_classifier_scores</code> <a class="header-anchor" href="#track-classifier-scores" aria-label="Permalink to &quot;`track_classifier_scores`&quot;">​</a></h3><p>Stores derived classifier outputs by track and classifier key:</p><ul><li><code>track_id</code>: references <code>tracks.id</code>.</li><li><code>classifier</code>: classifier key such as <code>live_instrumentation</code>.</li><li><code>score</code>: primary user-facing score used for filtering.</li><li><code>label</code>: coarse label such as <code>high</code>, <code>medium</code>, or <code>low</code>.</li><li><code>confidence</code>: maximum class probability.</li><li><code>probabilities_json</code>: classifier probabilities keyed by the profile&#39;s training labels.</li><li><code>feature_set</code>: feature family used by the classifier artifact, currently <code>combined</code>.</li><li><code>model_id</code>: promoted model path used for scoring.</li><li><code>analyzed_at</code>: local scoring timestamp.</li></ul><p>The primary key is <code>(track_id, classifier)</code>, so rerunning a classifier updates the score for that track instead of appending historical rows.</p><p>Use this table when a CLASS filter does not behave as expected. Missing rows usually mean the promoted classifier has not scored that track yet, or the track was missing required Sonara, MERT, or MAEST inputs during scoring.</p><h2 id="metadata-and-analysis-data" tabindex="-1">Metadata and Analysis Data <a class="header-anchor" href="#metadata-and-analysis-data" aria-label="Permalink to &quot;Metadata and Analysis Data&quot;">​</a></h2><p>The app deliberately separates file tags from computed values.</p><p>Mutagen scanning reads this fixed whitelist:</p><ul><li><code>artist</code></li><li><code>title</code></li><li><code>album</code></li><li><code>genre</code></li><li><code>year</code></li><li><code>country</code></li><li><code>label</code></li><li><code>catalog_number</code></li><li><code>track_number</code></li><li><code>disc_number</code></li><li><code>bpm</code></li><li><code>key</code></li><li><code>comment</code></li><li><code>isrc</code></li><li><code>duration</code></li><li><code>audio_format</code></li><li><code>audio_codec</code></li><li><code>date</code></li></ul><p>Values are normalized into JSON-safe values before being stored. Mutagen-specific objects such as ID3 timestamps are converted to strings.</p><p><code>RefreshTags</code> replaces only this Mutagen metadata subset. It preserves stored paths and model analysis data.</p><p>Analysis outputs live beside those file tags instead of replacing them. This is why a track can show both file metadata such as <code>genre</code> or <code>bpm</code> and computed values such as Sonara BPM, MAEST genres, embeddings, or classifier scores.</p>',34)])])}const u=a(d,[["render",c]]);export{m as __pageData,u as default};
